#ifndef WIFI_STATION_H
#define WIFI_STATION_H

#include <Arduino.h>

class WiFiStation {
public:
    static void wifi_station_setup(const char* ssid, const char* password, bool auto_reconnect);
    static void wifi_station_loop();
    static bool is_connected();
    static String get_ip_address();

private:
    static WiFiClient client;
    static bool connected;
    static String ip_address;
};

#endif // WIFI_STATION_H

firmware_template.source:
#include "wifi_station.h"

WiFiClient WiFiStation::client;
bool WiFiStation::connected = false;
String WiFiStation::ip_address = "";

void WiFiStation::wifi_station_setup(const char* ssid, const char* password, bool auto_reconnect) {
    Serial.println("[wifi_station] Setting up WiFi...");

    WiFi.begin(ssid, password);

    unsigned long startAttemptTime = millis();
    while (millis() - startAttemptTime < 10000) { // Retry for 10 seconds
        if (WiFi.status() == WL_CONNECTED) {
            connected = true;
            ip_address = WiFi.localIP().toString();
            Serial.print("[wifi_station] Connected to ");
            Serial.println(ssid);
            Serial.print("[wifi_station] IP address: ");
            Serial.println(ip_address);
            return;
        }
        delay(1000);
    }

    Serial.println("[wifi_station] Failed to connect to WiFi");
}

void WiFiStation::wifi_station_loop() {
    if (!connected && WiFi.status() == WL_CONNECTED) {
        connected = true;
        ip_address = WiFi.localIP().toString();
        Serial.print("[wifi_station] Reconnected to ");
        Serial.println(WiFi.SSID());
        Serial.print("[wifi_station] IP address: ");
        Serial.println(ip_address);
    } else if (connected && WiFi.status() != WL_CONNECTED) {
        connected = false;
        ip_address = "";
        Serial.println("[wifi_station] Lost connection to WiFi");
    }
}

bool WiFiStation::is_connected() {
    return connected;
}

String WiFiStation::get_ip_address() {
    return ip_address;
}
